(window.webpackJsonp=window.webpackJsonp||[]).push([[13],{450:function(t,i,a){"use strict";a.r(i);var e=a(1),n=Object(e.a)({},(function(){var t=this,i=t.$createElement,a=t._self._c||i;return a("ContentSlotsDistributor",{attrs:{"slot-key":t.$parent.slotKey}},[a("ul",[a("li",[t._v("背景音乐")])]),t._v(" "),a("iframe",{attrs:{frameborder:"no",border:"0",marginwidth:"0",marginheight:"0",width:"330",height:"86",src:"//music.163.com/outchain/player?type=2&id=31721420&auto=1&height=66"}}),t._v(" "),a("h1",{attrs:{id:"linux"}},[a("a",{staticClass:"header-anchor",attrs:{href:"#linux"}},[t._v("#")]),t._v(" Linux")]),t._v(" "),a("p",[t._v("说起Linux，你一定会联想到一只傻傻的企鹅坐在空气上。")]),t._v(" "),a("p",[a("img",{attrs:{src:"http://img.mp.itc.cn/upload/20160831/82283bd618134e90800c454783485776_th.jpeg",alt:"一只傻傻的企鹅坐在空气上"}})]),t._v(" "),a("p",[t._v("就在快要过去的2020年，linux29岁了。对29了。很明显，我这次文章的目的不是为了解密这只企鹅为什么可以坐在空气上。现在，进入正题。")]),t._v(" "),a("p",[t._v("linux,又叫GNU/linux,是一种免费使用和自由传播的类UNIX操作系统，其内核由林纳斯·本纳第克特·托瓦兹于1991年10月5日首次发布，它主要受到Minix和Unix思想的启发，是一个基于POSIX和Unix的多用户、多任务、支持多线程和多CPU的操作系统。它能运行主要的Unix工具软件、应用程序和网络协议。它支持32位和64位硬件。Linux继承了Unix以网络为核心的设计思想，是一个性能稳定的多用户网络操作系统。Linux有上百种不同的发行版，如基于社区开发的debian、archlinux，和基于商业开发的Red Hat Enterprise Linux、SUSE、oracle linux等。")]),t._v(" "),a("h2",{attrs:{id:"系统简史"}},[a("a",{staticClass:"header-anchor",attrs:{href:"#系统简史"}},[t._v("#")]),t._v(" 系统简史")]),t._v(" "),a("p",[t._v("Linux操作系统的诞生、发展和成长过程始终依赖着五个重要支柱：Unix操作系统、MINIX操作系统、GNU计划、POSIX标准和Internet网络。\n20世纪80年代，计算机硬件的性能不断提高，PC的市场不断扩大，当时可供计算机选用的操作系统主要有Unix、DOS和MacOS这几种。Unix价格昂贵，不能运行于PC；DOS显得简陋，且源代码被软件厂商严格保密；MacOS是一种专门用于苹果计算机的操作系统。此时，计算机科学领域迫切需要一个更加完善、强大、廉价和完全开放的操作系统。由于供教学使用的典型操作系统很少，因此当时在荷兰当教授的美国人AndrewS.Tanenbaum编写了一个操作系统，名为MINIX，为了向学生讲述操作系统内部工作原理。MINIX虽然很好，但只是一个用于教学目的的简单操作系统，而不是一个强有力的实用操作系统，然而最大的好处就是公开源代码。全世界学计算机的学生都通过钻研MINIX源代码来了解电脑里运行的MINIX操作系统，芬兰赫尔辛基大学大学二年级的学生Linus Torvalds就是其中一个，在吸收了MINIX精华的基础上，Linus于1991年写出了属于自己的Linux操作系统，版本为Linux0.01，是Linux时代开始的标志。他利用Unix的核心，去除繁杂的核心程序，改写成适用于一般计算机的x86系统，并放在网络上供大家下载，1994年推出完整的核心Version1.0，至此，Linux逐渐成为功能完善、稳定的操作系统，并被广泛使用。")]),t._v(" "),a("h2",{attrs:{id:"服务器"}},[a("a",{staticClass:"header-anchor",attrs:{href:"#服务器"}},[t._v("#")]),t._v(" 服务器")]),t._v(" "),a("p",[t._v("Linux服务器是设计出来进行业务处理应用的，在网络和计算机系统当中有广泛的应用，可以提供数据库管理和网络服务等内容，是一种性能非常高的和开源的服务器，在我国的计算机系统的客户端当中，有很多采用的就是Linux系统，其使用的范围非常广泛，用户体验反应较好。但是对于一些希望计算机应用性能比较高的单位而言，windows系统需要经常进行资源整合和碎片化管理，系统在配置的时候经常需要重新启动，这就无法避免产生停机的问题。同时，由于Linux系统的处理能力非常强悍，具备不可比拟的稳定性特征，因而Linux系统就不用经常进行重启，Linux系统的变化可以在配置的过程中实现，所以Linux服务器出现故障的概率比较小，所以很多企业组织在计算机配置的过程中经常使用Linux系统，从而降低服务器发生崩溃的可能性，很多企业在配置Linux系统的时候，都是通过减少服务器的故障发生率，实现企业业务的高效运转。")]),t._v(" "),a("h2",{attrs:{id:"系统内核的路由转发"}},[a("a",{staticClass:"header-anchor",attrs:{href:"#系统内核的路由转发"}},[t._v("#")]),t._v(" 系统内核的路由转发")]),t._v(" "),a("p",[t._v("Linux操作系统嵌入了TCP/IP协议栈，协议软件具有路由转发功能。路由转发依赖作为路由器的主机中安装多块网卡，当某一块网卡接收到数据包后，系统内核会根据数据包的目的IP地址，查询路由表，然后根据查询结果将数据包发送到另外一块网卡，最后通过此网卡把数据包发送出去。此主机的处理过程就是路由器完成的核心功能。\n通过修改Linux系统内核参数ip_forward的方式实现路由功能，系统使用sysctl命令配置与显示在/proc/sys目录中的内核参数。首先在命令行输入：cat/proc/sys/net/ipv4/ip_forwad，检查Linux内核是不是开启IP转发功能。如果结果为1，表明路由转发功能已经开启；如果结果为0，表明没有开启。出于安全考虑，Linux内核默认是禁止数据包路由转发的。在linux系统中，有临时和永久两种方法启用转发功能。\n临时启用：此种方法只对当前会话起作用，系统重启后不再启用。临时开启的命令格式：sysctl–wnet.ipv4.ip_forward=1。\n永久启用：此种永久性的启用IP转发功能，通过更改配置文件/etc/sysctl.conf中的语句行“net.ipv4.ip_forward=0”，修改为“net.ipv4.ip_forward=1”，保存配置文件后执行命令sysctl–p/etc/sysctl.conf，配置便立即启用。")]),t._v(" "),a("h2",{attrs:{id:"安全隐患及加固措施"}},[a("a",{staticClass:"header-anchor",attrs:{href:"#安全隐患及加固措施"}},[t._v("#")]),t._v(" 安全隐患及加固措施")]),t._v(" "),a("h3",{attrs:{id:"用户账户以及登录安全"}},[a("a",{staticClass:"header-anchor",attrs:{href:"#用户账户以及登录安全"}},[t._v("#")]),t._v(" 用户账户以及登录安全")]),t._v(" "),a("p",[t._v("删除多余用户和用户组。Linux是多用户操作系统，存在很多种不一样的角色系统账号，当安装完成操作系统之后，系统会默认为未添加许用户组及用户，若是部分用户或是用户组不需要，应当立即删除它们，否则黑客很有可能利用这些账号，对服务器实施攻击。具体保留哪些账号，可以依据服务器的用途来决定。\n关闭不需要的系统服务。操作系统安装完成之后，其会在安装的过程当中，会自主的启动各种类型的服务程序内容，对于长时间运行的服务器而言，其运行的服务程序越多，则系统的安全性就越低。所以，用户或是用户组就需要将一些应用不到的服务程序进行关闭，这对提升系统的安全性能，有着极大的帮助。\n密码安全策略。在Linux之下，远程的登录系统具备两种认证的形式：即密钥与密码认证。其中，密钥认证的形式，主要是将公钥储存在远程的服务器之上，私钥存储在本地。当进行系统登陆的时候，再通过本地的私钥，以及远程的服务器公钥，进行配对认证的操作，若是认证的匹配度一致，则用户便能够畅通无阻的登录系统。此类认证的方式，并不会受到暴力破解的威胁。与此同时，只需要确保本地私钥的安全，使其不会被黑客所盗取即可，攻击者便不能够通过此类认证方式登陆到系统中。所以，推荐使用密钥方式进行系统登陆。\n有效应用su、sudo命令。su命令的作用的是对用户进行切换。当管理员登录到系统之后，使用su命令切换到超级用户角色来执行一些需要超级权限的命令。但是由于超级用户的权限过大，同时，需要管理人员知道超级用户密码，因此su命令具有很严重的管理风险。\nsudo命令允许系统赋予普通用户一些超级权限，并且不需普通用户切换到超级用户。因此，在管理上应当细化权限分配机制，使用sudo命令为每一位管理员服务其特定的管理权限。")]),t._v(" "),a("h3",{attrs:{id:"远程访问及登陆认证安全"}},[a("a",{staticClass:"header-anchor",attrs:{href:"#远程访问及登陆认证安全"}},[t._v("#")]),t._v(" 远程访问及登陆认证安全")]),t._v(" "),a("p",[t._v("远程登录应用SSH登陆方式。telnet是一类存在安全隐患的登录认证服务，其在网络之上利用明文传输内容，黑客很容易通过截获telnet数据包，获得用户的登陆口令。并且telnet服务程序的安全验证方式存在较大的安全隐患，使其成为黑客攻击的目标。SSH服务则会将数据进行加密传输，能够防止DNS欺骗以及IP欺骗，并且传输的数据是经过压缩，在一定程度上保证了服务器远程连接的安全。\n文件系统的安全\n加固系统重要文件。在Linux系统中，如果黑客取得超级权限，那么他在操作系统里面就不会再有任何的限制地做任何事情。在这种情况下，一个加固的文件系统将会是保护系统安全的最后一道防线。管理员可通过chattr命令锁定系统一些重要文件或目录。\n文件权限检查与修改。如果操作系统当中的重要文件的权限设置不合理，则会对操作系统的安全性，产生最为直接的影响。所以，系统的运行维护人员需要及时的察觉到权限配置不合理的文件和目录，并及时修正，以防安全事件发生。\n安全设定/tmp、/var/tmp、/dev/shm。在该操作系统当中，其用于存放临时文件的目录，主要有两个，分别为/tmp与/var/tmp。它们有个共同特点，就是所有的用户可读可写和执行，这样就对系统产生了安全隐患。针对这两个目录进行设置，不允许这两个目录下执行应用程序。")]),t._v(" "),a("h3",{attrs:{id:"系统软件安全"}},[a("a",{staticClass:"header-anchor",attrs:{href:"#系统软件安全"}},[t._v("#")]),t._v(" 系统软件安全")]),t._v(" "),a("p",[t._v("绝大多数的服务器遭受攻击是因为系统软件或者应用程序有重大漏洞。黑客通过这些漏洞，可以轻松地侵入服务器。管理员应定期检查并修复漏洞。最常见的做法是升级软件，将软件保持在最新版本状态。这样就可以在一定程度上降低系统被入侵的可能性。")]),t._v(" "),a("h2",{attrs:{id:"开发工具"}},[a("a",{staticClass:"header-anchor",attrs:{href:"#开发工具"}},[t._v("#")]),t._v(" 开发工具")]),t._v(" "),a("p",[t._v("Linux已经成为工作、娱乐和个人生活等多个领域的支柱，人们已经越来越离不开它。在Linux的帮助下，技术的变革速度超出了人们的想象，Linux开发的速度也以指数规模增长。因此，越来越多的开发者也不断地加入开源和学习Linux开发地潮流当中。在这个过程之中，合适的工具是必不可少的，可喜的是，随着Linux的发展，大量适用于Linux的开发工具也不断成熟。")]),t._v(" "),a("h3",{attrs:{id:"容器"}},[a("a",{staticClass:"header-anchor",attrs:{href:"#容器"}},[t._v("#")]),t._v(" 容器")]),t._v(" "),a("p",[t._v("放眼现实，如今已经是容器的时代了。容器既极其容易部署，又可以方便地构建开发环境。如果针对的是特定的平台的开发，将开发流程所需要的各种工具都创建到容器映像中是一种很好的方法，只要使用这一个容器映像，就能够快速启动大量运行所需服务的实例。")]),t._v(" "),a("h3",{attrs:{id:"版本控制工具"}},[a("a",{staticClass:"header-anchor",attrs:{href:"#版本控制工具"}},[t._v("#")]),t._v(" 版本控制工具")]),t._v(" "),a("p",[t._v("如果正在开发一个大型项目，又或者参与团队开发，版本控制工具是必不可少的，它可以用于记录代码变更、提交代码以及合并代码。如果没有这样的工具，项目几乎无法妥善管理")]),t._v(" "),a("h3",{attrs:{id:"文本编辑工具"}},[a("a",{staticClass:"header-anchor",attrs:{href:"#文本编辑工具"}},[t._v("#")]),t._v(" 文本编辑工具")]),t._v(" "),a("p",[t._v("如果没有文本编辑器，在Linux上开发将会变得异常艰难。当然，文本编辑器之间孰优孰劣，具体还是要取决于开发者的需求。")]),t._v(" "),a("h3",{attrs:{id:"集成开发环境"}},[a("a",{staticClass:"header-anchor",attrs:{href:"#集成开发环境"}},[t._v("#")]),t._v(" 集成开发环境")]),t._v(" "),a("p",[t._v("有时候会需要比较两个文件的内容来找到它们之间的不同之处，它们可能是同一文件的两个不同副本（例如有一个经过编译，而另一个没有）。这种情况下，肯定不想要凭借肉眼来找出差异，而是想要使用像Med这样的工具。")]),t._v(" "),a("h2",{attrs:{id:"linux有多少"}},[a("a",{staticClass:"header-anchor",attrs:{href:"#linux有多少"}},[t._v("#")]),t._v(" Linux有多少？")]),t._v(" "),a("p",[a("img",{attrs:{src:"https://www.runoob.com/wp-content/uploads/2014/06/wKioL1bvVPWAu7hqAAEyirVUn3c446.jpg-wh_651x-s_3197843091.jpg",alt:"Linux主流"}})]),t._v(" "),a("p",[t._v("这还不算多的，说实在一点，Mac只是Linux的一个亚种....")]),t._v(" "),a("p",[a("img",{attrs:{src:"https://static.leiphone.com/uploads/new/images/20201111/5faaf4163142d.png?imageView2/2/w/740",alt:"MAC"}})]),t._v(" "),a("ul",[a("li",[t._v("那么，这么多的操作系统，我偏偏选了deepin来讲，是为什么？说实在一点因为这操作系统是一个超新星，它的外貌很是出众，看看官方的视频就知道了。")])]),t._v(" "),a("div",{staticStyle:{position:"relative","padding-bottom":"75%",width:"100%",height:"0"}},[a("iframe",{staticStyle:{position:"absolute",height:"100%",width:"100%"},attrs:{src:"//player.bilibili.com/player.html?aid=59860590&bvid=BV1Nt411n7E8&cid=104264193&page=1",scrolling:"no",border:"0",frameborder:"no",framespacing:"0",allowfullscreen:"true"}})]),t._v(" "),a("h1",{attrs:{id:"deepin"}},[a("a",{staticClass:"header-anchor",attrs:{href:"#deepin"}},[t._v("#")]),t._v(" Deepin")]),t._v(" "),a("p",[t._v("deepin（原名：Linux Deepin；中文通称：深度操作系统）是由武汉深之度科技有限公司在Debian基础上开发的Linux操作系统，其前身是Hiweed Linux操作系统，于2004年2月28日开始对外发行，可以安装在个人计算机和服务器中")]),t._v(" "),a("p",[t._v("deepin操作系统内部集成了deepin Desktop Environment（中文通称：深度桌面环境），并支持deepin store、deepin Music、deepin Movie等第一方应用软件。")]),t._v(" "),a("div",{staticClass:"tip warning faa-shake animated"},[a("p",[t._v("2019年，华为开始销售预装有deepin操作系统的笔记本电脑。")]),a("p")]),t._v(" "),a("p",[t._v("2020年，深之度正式发布了deepin v20版本，底层仓库升级到Debian 10.5，系统安装则采用了Kernel 5.4和Kernel 5.7双内核机制，同时用户操作界面也得到了大幅度的调整")]),t._v(" "),a("h2",{attrs:{id:"介绍"}},[a("a",{staticClass:"header-anchor",attrs:{href:"#介绍"}},[t._v("#")]),t._v(" 介绍")]),t._v(" "),a("p",[t._v("深度操作系统是基于Linux内核，以桌面应用为主的开源GNU/Linux操作系统，支持笔记本、台式机和一体机。深度操作系统（deepin）包含深度桌面环境（DDE）和近30款深度原创应用，及数款来自开源社区的应用软件，支撑广大用户日常的学习和工作。另外，通过深度商店还能够获得近千款应用软件的支持，满足您对操作系统的扩展需求。深度操作系统由专业的操作系统研发团队和深度技术社区共同打造，其名称来自深度技术社区名称“deepin”一词，意思是对人生和未来深刻的追求和探索。\n深度操作系统（deepin）是中国第一个具备国际影响力的Linux发行版本，截止至2019年7月25日，深度操作系统支持33种语言，用户遍布除了南极洲的其它六大洲。深度桌面环境（deepinDDE）和大量的应用软件被移植到了包括Fedora、Ubuntu、Arch等十余个国际Linux发行版和社区，在开源操作系统统计网站DistroWatch上，deepin长期位于世界前十。")]),t._v(" "),a("p",[t._v("Deepin 12.12 正式版本将搭载一个全新的桌面环境。该桌面环境由Deepin 团队开发，以轻型、美观、稳定等作为设计目标。新桌面环境使用 Compiz 作为默认的窗口管理器。\n系统设置模块全部进行代码重写，不再使用“GNOME 控制中心”(gnome control center)，系统设置中心也会采用 Deepin UI 库作为界面库。深度音乐播放器、影音播放器最初的版本也是基于此界面库进行外观设计。最新版本的深度截图工具也采用了 Deepin UI 库。\n新的桌面环境不仅对Deepin社区，也会对其他操作系统社区带来令人刺激的变革。国际社区也将看到一个概念独特、回归用户操作的桌面环境，一切都会变得熟悉。\n深度桌面环境\n应用程序一览无余\n应用程序概览视图，可通过点击屏幕左下角的“应用程序启动器（Launcher）”按钮，或 Alt+F2 组合键打开。它可以让您快速查找并启动应用程序。\n新底部 Dock，快速打开常用程序\n新Dock主要由传统的Dock+托盘（系统级别+程序级别）两部分组成。点击Dock面板即可弹出“系统级托盘显示”和“Dock显示”功能选项，可以让用户自定义系统级托盘的显示和Dock的显示方式。\n传统的底部 Dock，快速打开常用程序（就是屏幕底部的水平条）。它包括了应用程序启动器（Launcher）、显示桌面按钮，常用应用程序快捷方式和系统托盘等部分。支持应用程序快捷方式的添加与删除，并显示已打开应用程序的窗口列表。\n简洁的消息通知\n它会及时提示您来自聊天工具或其他应用程序、系统发出的通知，通知显示区域为屏幕右下角。消息托盘功能会在之后版本中继续完善。\n深度系统设置\n深度系统设置（Deepin System Settings），采用 Deepin UI 图形库，对各个设置模块进行了全新设计，主要包括显示、声音、个性化、电源、账户、网络等系统设置模块，可以方便地对系统各模块进行个性化设置。\n下面重点介绍几个方面:\n支持自动调节屏幕亮度。\n如果您的电脑配有采光设备，该功能可根据外界光亮程度自动调整屏幕亮度，以节省电源。\n个性化主题和壁纸设置。\na: 系统默认提供四组精彩壁纸，可根据您的喜好进行切换。 b: 支持壁纸随机播放，可设置图片切换的间隔时间。 c: 集成爱壁纸HD在线壁纸模块。\n支持农历日期显示。\n在日期时间模块，增加了对中国农历日期的支持，并支持显示国际性节日与中国传统节日。\n更加方便的网络设置。\n各个网络设置类型，如有线、拨号、移动等网络分类一目了然，设置界面极其简洁，可以帮助您快速设置网络。\n快速设置用户头像：支持深度截图工具与摄像头拍摄。\n可以使用深度截图工具截取屏幕并进行简单的编辑后设置为用户头像，也可以通过摄像头拍摄后直接设置为头像。")]),t._v(" "),a("div",{staticClass:"tip error faa-spin animated"},[a("p",[t._v("很官方的发言....")]),a("p")]),t._v(" "),a("h3",{attrs:{id:"深度原生应用"}},[a("a",{staticClass:"header-anchor",attrs:{href:"#深度原生应用"}},[t._v("#")]),t._v(" 深度原生应用：")]),t._v(" "),a("p",[t._v("深度文件管理器、深度系统监视器、深度字体安装器、深度备份还原工具、深度取色器、深度商店、深度录屏、深度录音、深度截图、深度终端、深度看图、深度影院、深度音乐、深度云打印、深度云扫描、深度日历、深度远程协助、深度启动盘制作工具、深度安装器……")]),t._v(" "),a("h2",{attrs:{id:"如何安装deepin"}},[a("a",{staticClass:"header-anchor",attrs:{href:"#如何安装deepin"}},[t._v("#")]),t._v(" 如何安装deepin?")]),t._v(" "),a("div",{staticStyle:{position:"relative","padding-bottom":"75%",width:"100%",height:"0"}},[a("iframe",{staticStyle:{position:"absolute",height:"100%",width:"100%"},attrs:{src:"//player.bilibili.com/player.html?aid=414788186&bvid=BV1DV41117PN&cid=240437958&page=1",scrolling:"no",border:"0",frameborder:"no",framespacing:"0",allowfullscreen:"true"}})]),t._v(" "),a("ul",[a("li",[t._v("还是看官方的视频吧......")])]),t._v(" "),a("div",{staticClass:"tip error faa-spin animated"},[a("p",[t._v("文章到此结束，谢谢你看到了这里...送个大风车给你吧！不要谢我。")]),a("p")]),t._v(" "),a("h1",{attrs:{id:"我是"}},[a("a",{staticClass:"header-anchor",attrs:{href:"#我是"}},[t._v("#")]),t._v(" 我是")]),t._v(" "),a("p",[a("img",{attrs:{src:"https://github-readme-stats.vercel.app/api?username=xixi-cmd&show_icons=true",alt:"Github Stats"}})])])}),[],!1,null,null,null);i.default=n.exports}}]);